import React, { useState } from 'react';

function QuestionForm({ onSubmit }) {
  const [answers, setAnswers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleInputChange = (index, value) => {
    const newAnswers = [...answers];
    newAnswers[index] = value;
    setAnswers(newAnswers);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    const apiKey = 'TU_API_KEY_AQUÍ'; // 👈 Reemplaza esto por tu API key

    try {
      const response = await fetch('https://api.openai.com/v1/chat/completions', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${apiKey}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          model: "gpt-3.5-turbo",
          messages: [
            {
              role: "system",
              content: "Eres un reclutador de Recursos Humanos que analiza entrevistas de postulantes."
            },
            {
              role: "user",
              content: `Evalúa profesionalmente estas respuestas de entrevista: ${answers.join(" | ")}. Da una conclusión si el candidato es 'Apto' o 'No apto' y proporciona un breve feedback.`
            }
          ],
          max_tokens: 200,
        }),
      });

      const result = await response.json();

      if (!response.ok) {
        throw new Error(result.error?.message || 'Error al conectar con la API');
      }

      const analysis = result.choices[0].message.content;
      onSubmit(analysis);

    } catch (err) {
      console.error('Error al conectar con la API', err);
      setError('Hubo un problema al procesar las respuestas.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      {[
        "¿Por qué estás interesado en este puesto?",
        "¿Cuáles son tus principales fortalezas?",
        "Describe una situación difícil en el trabajo y cómo la resolviste.",
        "¿Cómo manejas el trabajo bajo presión?",
        "¿Qué esperas lograr en los próximos 5 años?",
        "¿Prefieres trabajar en equipo o de forma individual? ¿Por qué?",
        "¿Cómo te mantienes actualizado en tu área profesional?",
        "¿Tienes experiencia trabajando con herramientas tecnológicas específicas?"
      ].map((question, index) => (
        <div key={index}>
          <label>{question}</label>
          <input
            type="text"
            onChange={(e) => handleInputChange(index, e.target.value)}
            required
          />
        </div>
      ))}

      <button type="submit" disabled={loading}>
        {loading ? 'Evaluando...' : 'Enviar respuestas'}
      </button>
      {error && <p>{error}</p>}
    </form>
  );
}

export default QuestionForm;
